 44→        if(message){
 45→          // console.log(message.message)
 46→        }
 47→
 48→      }
 49→        editor.update(() => {
 50→            const state = editor.getEditorState().toJSON();
 51→            // console.log(state)
 52→
 53→            const root = $getRoot();
 54→            root.clear();
 55→            onClose();
 56→        })
 57→    }, [editor, onClose, session?.access_token, uploadedImagePaths])
 58→
 59→    const handleCloseEditorOnSave = useCallback(async() => {
 60→      editor.update(() => {
 61→            const state = editor.getEditorState().toJSON();
 62→            // console.log(state)
 63→
 64→            const root = $getRoot();
