 95→
 96→    const location = useLocation();
 97→    const { journalId } = useParams();
 98→    const statePostData = location.state;
 99→    const shouldFetchPost = !!journalId && (!statePostData || !statePostData?.postType);
100→
101→    const { data: fetchedJournalData, isLoading: isLoadingJournalById } = useQuery({
102→        queryKey: ['journalById', journalId, user?.userData?.[0]?.id],
103→        queryFn: ({ queryKey }) => getJournalById(queryKey[1], queryKey[2]),
104→        enabled: shouldFetchPost,
105→        staleTime: 1000 * 60 * 5,
106→        refetchOnWindowFocus: false,
107→    });
108→
109→    const postData = useMemo(() => {
110→        const journal = fetchedJournalData?.journal;
111→        if(journal){
112→            const postType = journal?.post_type || 'text';
113→            const parsedContent = ParseContent(journal?.content);
114→            const wholeText = parsedContent?.wholeText || '';
115→
116→            return {
117→                postType: postType,
118→                content: journal?.content,
119→                wholeText: wholeText,
120→                title: journal?.title,
121→                userId: journal?.users?.id || journal?.user_id,
122→                name: journal?.users?.name,
123→                avatar: journal?.users?.image_url,
124→                created_at: journal?.created_at,
125→                journalId: journal?.id,
126→                isLiked: journal?.has_liked,
127→                commentsCount: journal?.comment_count?.[0]?.count || 0,
128→                isBookmarked: journal?.has_bookmarked,
129→                likesCount: journal?.like_count?.[0]?.count || 0,
130→                bookmarksCount: journal?.bookmark_count?.[0]?.count || 0,
131→                badge: journal?.users?.badge,
132→                isRepost: journal?.is_repost === true,
133→                repostCaption: journal?.repost_caption || '',
134→                repostSource: journal?.repost_source || null,
135→                userReaction: journal?.user_reaction || null,
136→                reactionCount: journal?.reaction_count?.[0]?.count || 0
137→            };
138→        }
139→
140→        if(!statePostData){
141→            return null;
142→        }
143→
144→        const inferredPostType = statePostData?.postType || 'text';
145→        const parsedContent = ParseContent(statePostData?.content);
146→
147→        return {
148→            postType: inferredPostType,
149→            content: statePostData?.content,
150→            wholeText: statePostData?.wholeText || parsedContent?.wholeText || '',
151→            title: statePostData?.title,
